using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_04c8eb84a14d4cb096375d0ba6365da2.Auth;

/// <summary>
/// Persists the authentication state so the WebAssembly client can
/// restore it after the runtime takes over from server-side prerendering.
/// </summary>
public class PersistingServerAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentComponentState;
    private readonly AuthenticationStateProvider _inner;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingServerAuthenticationStateProvider(
        PersistentComponentState persistentComponentState,
        HardcodedAuthenticationStateProvider inner)
    {
        _persistentComponentState = persistentComponentState;
        _inner = inner;

        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentComponentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => _inner.GetAuthenticationStateAsync();

    private void OnAuthenticationStateChanged(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authenticationStateTask ?? GetAuthenticationStateAsync();
        var state = await authState;
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var name = principal.FindFirst(ClaimTypes.Name)?.Value;
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            if (name is not null)
            {
                _persistentComponentState.PersistAsJson(nameof(UserInfo), new UserInfo
                {
                    Name = name,
                    Roles = roles,
                });
            }
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

public class UserInfo
{
    public required string Name { get; set; }
    public string[] Roles { get; set; } = [];
}

